#include <stdio.h>
#include <string.h>
#include <ctype.h>

void trim(char *s) {
    int start = 0, end = strlen(s) - 1;
    while (start <= end && isspace((unsigned char)s[start])) start++;
    while (end >= start && isspace((unsigned char)s[end])) end--;
    int i, j = 0;
    for (i = start; i <= end; ++i) s[j++] = s[i];
    s[j] = '\0';
}

void replaceCats(const char *src, char *dst) {
    while (*src) {
        if (strncmp(src, "cats", 4) == 0) {
            strcpy(dst, "cars");
            dst += 4;
            src += 4;
        } else {
            *dst++ = *src++;
        }
    }
    *dst = '\0';
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume newline after T
    char line[256];
    for (int tc = 0; tc < T; ++tc) {
        if (!fgets(line, sizeof(line), stdin)) break;
        line[strcspn(line, "\n")] = '\0'; // remove newline
        trim(line);
        char corrected[256];
        replaceCats(line, corrected);
        printf("Original sentence: %s\n", line);
        printf("Auto-Corrected sentence: %s\n", corrected);
    }
    return 0;
}

