import java.io.*;
import java.util.*;

public class Main {
    private static String trim(String s) {
        int start = 0, end = s.length();
        while (start < end && Character.isWhitespace(s.charAt(start))) start++;
        while (end > start && Character.isWhitespace(s.charAt(end - 1))) end--;
        return s.substring(start, end);
    }

    private static String replaceCats(String s) {
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < s.length(); ) {
            if (i + 4 <= s.length() && s.substring(i, i + 4).equals("cats")) {
                sb.append("cars");
                i += 4;
            } else {
                sb.append(s.charAt(i++));
            }
        }
        return sb.toString();
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String first = br.readLine();
        if (first == null) return;
        int T = Integer.parseInt(first.trim());
        for (int tc = 0; tc < T; ++tc) {
            String line = br.readLine();
            if (line == null) line = "";
            String original = trim(line);
            String corrected = replaceCats(original);
            System.out.println("Original sentence: " + original);
            System.out.println("Auto-Corrected sentence: " + corrected);
        }
    }
}

