#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    T = int(data[0].strip())
    lines = data[1:1+T]
    for line in lines:
        original = line.strip()
        corrected = original.replace('cats', 'cars')
        print(f"Original sentence: {original}")
        print(f"Auto-Corrected sentence: {corrected}")

if __name__ == "__main__":
    main()

